import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { MapPin, Coins, Package } from 'lucide-react';

export default function Profile() {
  const [myListings, setMyListings] = useState([]);
  const [name] = useState("Arjun Das");

  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem('myListings')) || [];
    setMyListings(saved);
  }, []);

  return (
    <div className="p-10 max-w-5xl mx-auto space-y-10">
      <div className="bg-white dark:bg-slate-900 rounded-[40px] p-10 shadow-sm border border-slate-50 dark:border-slate-800 flex items-center gap-10 transition-colors">
        <div className="w-32 h-32 bg-teal-50 dark:bg-teal-900/30 rounded-full flex items-center justify-center text-teal-600 text-4xl font-black border-4 border-white dark:border-slate-800 shadow-xl">{name[0]}</div>
        <div className="flex-1">
          <h1 className="text-4xl font-black text-slate-900 dark:text-white">{name}</h1>
          <p className="text-slate-400 font-bold mt-2 flex items-center gap-2"><MapPin size={18} className="text-teal-600"/> Kadavanthra, Kochi</p>
        </div>
        <div className="bg-slate-900 dark:bg-teal-600 text-white px-8 py-4 rounded-[24px] text-center">
          <p className="text-[10px] font-black uppercase tracking-widest opacity-70">Balance</p>
          <p className="text-2xl font-black">1450 WTK</p>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-[40px] p-10 border border-slate-50 dark:border-slate-800 shadow-sm">
        <h3 className="text-xl font-black text-slate-900 dark:text-white mb-8 flex items-center gap-3">
          <Package className="text-teal-600" /> My Active Listings ({myListings.length})
        </h3>
        <div className="space-y-4">
          {myListings.map(item => (
            <div key={item.id} className="flex items-center justify-between p-6 bg-slate-50 dark:bg-slate-800/50 rounded-3xl border border-transparent hover:border-teal-500/20 transition-all">
              <span className="font-bold text-slate-700 dark:text-slate-200">{item.title}</span>
              <div className="flex items-center gap-6">
                <span className="text-slate-400 text-sm font-bold">{item.date}</span>
                <span className="text-teal-600 font-black px-4 py-2 bg-white dark:bg-slate-900 rounded-xl shadow-sm">{item.wtk} WTK</span>
              </div>
            </div>
          ))}
          {myListings.length === 0 && <p className="text-slate-400 text-center py-10">Your published items will appear here.</p>}
        </div>
      </div>
    </div>
  );
}
